#!/usr/bin/env bash
# Capture raw IQ with rtl_sdr, write a JSON sidecar (center rate + paths),
# then run rtlsdr-mock-sim replay so hardware and the TS lab share one command.
#
# Run from anywhere; resolves the Gnosis package root automatically.
# Requires: rtl_sdr (e.g. macOS: brew install librtlsdr), pnpm deps installed.
#
# Env (all optional):
#   RTL_SDR              Path to rtl_sdr binary (default: PATH, then Homebrew prefixes)
#   RTLSDR_HW_FREQ_HZ    Tuner center Hz (default: 162400000, NOAA WX-ish example band)
#   RTLSDR_HW_IQ_RATE    Sample rate Hz (default: 2048000)
#   RTLSDR_HW_SAMPLES    IQ pairs to read -n (default: 409600 ~0.2 s at 2.048 Msps)
#   RTLSDR_HW_DEVICE     rtl_sdr -d index if multiple dongles
#   RTLSDR_HW_OUT_DIR    Capture + artifact directory (default: .qa-artifacts/rtlsdr under package root)
#   RTLSDR_HW_CAPTURE_PATH  Override .u8 output path
#   RTLSDR_HW_META_PATH     Override sidecar JSON path
#   RTLSDR_HW_WAV_OUT       Replay WAV output path

set -euo pipefail

GNOSIS_PKG="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
cd "$GNOSIS_PKG"

resolve_rtl_sdr() {
  if [[ -n "${RTL_SDR:-}" ]]; then
    if [[ ! -x "$RTL_SDR" ]]; then
      echo "rtl_sdr: RTL_SDR is set but not executable: $RTL_SDR" >&2
      return 1
    fi
    printf '%s' "$RTL_SDR"
    return 0
  fi
  if command -v rtl_sdr >/dev/null 2>&1; then
    command -v rtl_sdr
    return 0
  fi
  local c
  for c in /opt/homebrew/bin/rtl_sdr /usr/local/bin/rtl_sdr; do
    if [[ -x "$c" ]]; then
      printf '%s' "$c"
      return 0
    fi
  done
  return 1
}

RTL_BIN="$(resolve_rtl_sdr)" || {
  echo "rtl_sdr not found. Install librtlsdr (e.g. brew install librtlsdr) or set RTL_SDR=/path/to/rtl_sdr" >&2
  exit 1
}

FREQ="${RTLSDR_HW_FREQ_HZ:-162400000}"
RATE="${RTLSDR_HW_IQ_RATE:-2048000}"
NSAMP="${RTLSDR_HW_SAMPLES:-409600}"
OUT_DIR="${RTLSDR_HW_OUT_DIR:-${GNOSIS_PKG}/.qa-artifacts/rtlsdr}"
CAPTURE="${RTLSDR_HW_CAPTURE_PATH:-${OUT_DIR}/hardware-capture.u8}"
META="${RTLSDR_HW_META_PATH:-${OUT_DIR}/hardware-capture.meta.json}"
WAV_OUT="${RTLSDR_HW_WAV_OUT:-${OUT_DIR}/hardware-replay.wav}"

mkdir -p "$OUT_DIR"

RTL_ARGS=(-f "$FREQ" -s "$RATE" -n "$NSAMP")
if [[ -n "${RTLSDR_HW_DEVICE:-}" ]]; then
  RTL_ARGS+=(-d "$RTLSDR_HW_DEVICE")
fi

echo "rtlsdr-hardware-loop: using $RTL_BIN" >&2
echo "rtlsdr-hardware-loop: capture center=${FREQ} Hz rate=${RATE} Hz samples=${NSAMP} -> ${CAPTURE}" >&2

"$RTL_BIN" "${RTL_ARGS[@]}" "$CAPTURE"

CAPTURE_ABS="$(cd "$(dirname "$CAPTURE")" && pwd)/$(basename "$CAPTURE")"
WAV_ABS="$(cd "$(dirname "$WAV_OUT")" && pwd)/$(basename "$WAV_OUT")"
META_ABS="$(cd "$(dirname "$META")" && pwd)/$(basename "$META")"
ISO="$(date -u +"%Y-%m-%dT%H:%M:%SZ")"

export RTL_META_ABS="$META_ABS"
export RTL_CAPTURE_ABS="$CAPTURE_ABS"
export RTL_BIN_PATH="$RTL_BIN"
export RTL_ISO="$ISO"
export RTL_FREQ="$FREQ"
export RTL_RATE="$RATE"
export RTL_NSAMP="$NSAMP"

node -e '
const fs = require("fs");
const o = {
  centerHz: Number(process.env.RTL_FREQ),
  iqRateHz: Number(process.env.RTL_RATE),
  iqSamplePairs: Number(process.env.RTL_NSAMP),
  capturePath: process.env.RTL_CAPTURE_ABS,
  rtl_sdr: process.env.RTL_BIN_PATH,
  capturedAtIso: process.env.RTL_ISO,
};
fs.writeFileSync(process.env.RTL_META_ABS, JSON.stringify(o, null, 2) + "\n");
'

echo "rtlsdr-hardware-loop: wrote sidecar ${META_ABS}" >&2
echo "rtlsdr-hardware-loop: replay -> ${WAV_ABS}" >&2

pnpm run rtlsdr-mock-sim -- replay --iq-file "$CAPTURE_ABS" --iq-rate "$RATE" --wav-out "$WAV_ABS"

echo "rtlsdr-hardware-loop: done (IQ ${CAPTURE_ABS}, WAV ${WAV_ABS}, meta ${META_ABS})" >&2
